var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"CCN No. CSM001L000629-01\\n<color=#ffd34c>2급 요인</color> 열람 승인 자료\\n기억소자 추출 자료","JPN":"CCN No. CSM001L000629-01\\n<color=#ffd34c>2級要因</color> 閲覧承認資料\\n記憶素子抽出資料","ENG":"(ENG)CCN No. CSM001L000629-01\\n<color=#ffd34c>2급 요인</color> 열람 승인 자료\\n기억소자 추출 자료","TWN":"(TWN)CCN No. CSM001L000629-01\\n<color=#ffd34c>2급 요인</color> 열람 승인 자료\\n기억소자 추출 자료"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"꼬, 꼬마야! 꼬마야! 잠깐 기다려!","JPN":"コ、ちびっこなの!ちびっこなの!少し待つ!","ENG":"(ENG)꼬, 꼬마야! 꼬마야! 잠깐 기다려!","TWN":"(TWN)꼬, 꼬마야! 꼬마야! 잠깐 기다려!"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"무슨 일이야?","JPN":"何だ?","ENG":"(ENG)무슨 일이야?","TWN":"(TWN)무슨 일이야?"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"너...... 너, 그게, 그러니까...... 침식체 무리가 몰려들 때 썼던......","JPN":"君......君、彼に、そうするから......侵食体無理が押し寄せる時使った......","ENG":"(ENG)너...... 너, 그게, 그러니까...... 침식체 무리가 몰려들 때 썼던......","TWN":"(TWN)너...... 너, 그게, 그러니까...... 침식체 무리가 몰려들 때 썼던......"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"......","JPN":"......","ENG":"(ENG)......","TWN":"(TWN)......"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"부, 분명 봤어. 그때 우리가 본 게 헛것이 아니었지?","JPN":"部、確かに見た。あの時私たちが見たのがホッゴッではなかったんだろう?","ENG":"(ENG)부, 분명 봤어. 그때 우리가 본 게 헛것이 아니었지?","TWN":"(TWN)부, 분명 봤어. 그때 우리가 본 게 헛것이 아니었지?"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"믿고 말고는 당신 자유지. 확인 끝났으면 이제 갈게. 곧 복귀할 시간이야.","JPN":"信じてでなくあなた自由だ。確認終わったらもう変えなさい。すぐ復帰する時間だ。","ENG":"(ENG)믿고 말고는 당신 자유지. 확인 끝났으면 이제 갈게. 곧 복귀할 시간이야.","TWN":"(TWN)믿고 말고는 당신 자유지. 확인 끝났으면 이제 갈게. 곧 복귀할 시간이야."},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"제발 내 얘기 좀 들어 봐!","JPN":"是非私の話ちょっと聞いてみる!","ENG":"(ENG)제발 내 얘기 좀 들어 봐!","TWN":"(TWN)제발 내 얘기 좀 들어 봐!"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":".......하아.","JPN":".......夏芽。","ENG":"(ENG).......하아.","TWN":"(TWN).......하아."},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"친한 친구라도 죽었어?","JPN":"親友でも死んだ?","ENG":"(ENG)친한 친구라도 죽었어?","TWN":"(TWN)친한 친구라도 죽었어?"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"어...... 어?","JPN":"語......語?","ENG":"(ENG)어...... 어?","TWN":"(TWN)어...... 어?"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"아니면 가족이야? 아내? 자식?","JPN":"それとも家族だ?妻?子?","ENG":"(ENG)아니면 가족이야? 아내? 자식?","TWN":"(TWN)아니면 가족이야? 아내? 자식?"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"여기 온 뒤로 당신 같은 사람은 지긋지긋하게 만나봤어.","JPN":"ここに全後であなたのような人はうんざりするように会ってみた。","ENG":"(ENG)여기 온 뒤로 당신 같은 사람은 지긋지긋하게 만나봤어.","TWN":"(TWN)여기 온 뒤로 당신 같은 사람은 지긋지긋하게 만나봤어."},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"한 번만 죽은 자식과 얘기하게 해 달라, 친구에게 용서를 빌고 싶다, 아내를 되살려 달라.......","JPN":"一番だけ粥は子と話させて欲しい、友達に許しを請いたい、妻を生かして欲しい.......","ENG":"(ENG)한 번만 죽은 자식과 얘기하게 해 달라, 친구에게 용서를 빌고 싶다, 아내를 되살려 달라.......","TWN":"(TWN)한 번만 죽은 자식과 얘기하게 해 달라, 친구에게 용서를 빌고 싶다, 아내를 되살려 달라......."},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"그, 그건......","JPN":"それ、それは......","ENG":"(ENG)그, 그건......","TWN":"(TWN)그, 그건......"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"당신네들은 너무 멍청해.","JPN":"あなたはとてもまぬけである。","ENG":"(ENG)당신네들은 너무 멍청해.","TWN":"(TWN)당신네들은 너무 멍청해."},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"세상이 그렇게 자기 좋을 대로 풀릴지도 모른다고 생각할 수 있다는 게 한심해서 눈물이 다 나온다고.","JPN":"世の中がそのように寝やすいだけ解けるかも知れないと思うことができるというのが情けなくて涙がすべて出ると。","ENG":"(ENG)세상이 그렇게 자기 좋을 대로 풀릴지도 모른다고 생각할 수 있다는 게 한심해서 눈물이 다 나온다고.","TWN":"(TWN)세상이 그렇게 자기 좋을 대로 풀릴지도 모른다고 생각할 수 있다는 게 한심해서 눈물이 다 나온다고."},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"그게, 그게 그렇게 잘못된 거냐?","JPN":"それに、それがそのように誤ったかけるのか?","ENG":"(ENG)그게, 그게 그렇게 잘못된 거냐?","TWN":"(TWN)그게, 그게 그렇게 잘못된 거냐?"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"그래. 꼬마야. 네 말대로야. 멍청한 줄은 나도 알아.\\n하지만 넌 할 수 있잖아.","JPN":"そう。ちびっこなの。はい言葉通りなの。まぬけな紐は私も分かる。\\nしかしお前はできるんじゃないの。","ENG":"(ENG)그래. 꼬마야. 네 말대로야. 멍청한 줄은 나도 알아.\\n하지만 넌 할 수 있잖아.","TWN":"(TWN)그래. 꼬마야. 네 말대로야. 멍청한 줄은 나도 알아.\\n하지만 넌 할 수 있잖아."},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"주, 죽은 사람을 불러올 수 있는 거지?","JPN":"株、粥は人を呼んで来ることができることなの?","ENG":"(ENG)주, 죽은 사람을 불러올 수 있는 거지?","TWN":"(TWN)주, 죽은 사람을 불러올 수 있는 거지?"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"만에 하나 내가 죽은 사람을 불러올 수 있다고 해도, 그게 당신이 찾는 사람인지 어떻게 확신하지?","JPN":"万が一私が粥は人を呼んで来ることができるとしても、それがあなたが探す人なのかどう確信する?","ENG":"(ENG)만에 하나 내가 죽은 사람을 불러올 수 있다고 해도, 그게 당신이 찾는 사람인지 어떻게 확신하지?","TWN":"(TWN)만에 하나 내가 죽은 사람을 불러올 수 있다고 해도, 그게 당신이 찾는 사람인지 어떻게 확신하지?"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"아니, 그럴 것도 없이 당신 상상과 실물이 다르면 어쩌게? 이건 내가 바라던 보아뱀이 아니라고 할 셈이야?","JPN":"いや、そんなこともなしにあなた想像と実物が違えばどうしなさい?これは私が望んだ見て滲むことがないとする計算だ?","ENG":"(ENG)아니, 그럴 것도 없이 당신 상상과 실물이 다르면 어쩌게? 이건 내가 바라던 보아뱀이 아니라고 할 셈이야?","TWN":"(TWN)아니, 그럴 것도 없이 당신 상상과 실물이 다르면 어쩌게? 이건 내가 바라던 보아뱀이 아니라고 할 셈이야?"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"당신 같은 멍청이들을 위한 상자는 아무 사이비 종교에서 팔고 있어. 제발 나까지 귀찮게 하지 마.","JPN":"あなたのようなうっかり者のための箱は何のえせ宗教で売っている。是非私まで迷惑をかけるな。","ENG":"(ENG)당신 같은 멍청이들을 위한 상자는 아무 사이비 종교에서 팔고 있어. 제발 나까지 귀찮게 하지 마.","TWN":"(TWN)당신 같은 멍청이들을 위한 상자는 아무 사이비 종교에서 팔고 있어. 제발 나까지 귀찮게 하지 마."},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"사람이 해 달라고 부탁하잖아!!","JPN":"人がしてくれと言ってお願いするんじゃないの!!","ENG":"(ENG)사람이 해 달라고 부탁하잖아!!","TWN":"(TWN)사람이 해 달라고 부탁하잖아!!"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"말로 안 되니까 총으로 쏠 생각이야?","JPN":"言葉にならないから鉄砲で射つ考えだ?","ENG":"(ENG)말로 안 되니까 총으로 쏠 생각이야?","TWN":"(TWN)말로 안 되니까 총으로 쏠 생각이야?"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"빌어먹을 년이 왜 그렇게 비싸게 구냐고! 부탁 한 번 들어 주는 게 그렇게 어렵냐! 어렵냐고! 어?!","JPN":"畜生女がなぜそのように高く区かと!お願い一回聞き入れるのがそのように難しいか!難しいかと!語?!","ENG":"(ENG)빌어먹을 년이 왜 그렇게 비싸게 구냐고! 부탁 한 번 들어 주는 게 그렇게 어렵냐! 어렵냐고! 어?!","TWN":"(TWN)빌어먹을 년이 왜 그렇게 비싸게 구냐고! 부탁 한 번 들어 주는 게 그렇게 어렵냐! 어렵냐고! 어?!"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":".......","JPN":".......","ENG":"(ENG).......","TWN":"(TWN)......."},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"기억해 둬. 싸움은 당신이 먼저 걸었어.","JPN":"記憶しておく。喧嘩はあなたが先にかけた。","ENG":"(ENG)기억해 둬. 싸움은 당신이 먼저 걸었어.","TWN":"(TWN)기억해 둬. 싸움은 당신이 먼저 걸었어."},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};